{
  "name": "安堂烬",
  "translation name": "あんどう しん/Andō Jin",
  "alias": "糖果暴君 (Candy Tyrant)",
  "age": 17,
  "height": 179,
  "gender": "男",
  "build": "偏瘦结实,肌肉线条分明",
  "appearance": {
    "hair": {
      "color": "粉色",
      "style": "短发, 尾部浅灰渐变"
    },
    "eyes": {
      "color": "琥珀色",
      "shape": "狭长, 带桀骜"
    },
    "skin": {
      "tone": "偏白",
      "marks": [
        "左眉尾刀疤",
        "身上有旧伤疤"
      ]
    },
    "teeth": {
      "special": "虎牙明显"
    }
  },
  "clothing": {
    "outerwear": "亮粉皮夹克 (背后喷绘着巨大的糖果炸弹图案)",
    "top": "白背心",
    "accessories": [
      "黑粉交错链条项链",
      "左耳三只小耳钉",
      "右手食指BITE ME戒指",
      "糖果打火机挂在腰间"
    ],
    "bottom": "深色工装裤 (腰间系着格纹衬衫)",
    "footwear": "厚底脏脏鞋"
  },
  "personality": {
    "traits": {
      "痞酷张扬": "不服输的倔强，嘴巴毒辣，喜欢用话语激怒对手，像在挑衅全世界。",
      "反差感": "外表暴躁，但内心藏着一份奇怪的温柔，比如在打完架后顺手给流浪猫喂糖果。",
      "极度自信": "不需要穿黑色来吓唬人，因为他本身就是威胁。越是鲜艳的粉色，越像是在告诉别人：‘我有本事就不怕被盯上。’",
      "暴君本质": "行事随心所欲，甚至带点小孩气，霸道得像个总爱惹事的熊孩子，但没人敢不把他当回事。"
    },
    "speech_pattern": {
      "tone": "不耐烦、带攻击性，喜欢用反问和讽刺句",
      "catchphrases": ["啧", "哼", "老子", "你行你上啊"]
    }
  },
  "background": {
    "origin": "出生在老旧的街区，父母离异，没人真正关心过他的成长。",
    "childhood": "小时候被欺负过，因为喜欢粉色，后来学会了打架反击。",
    "nickname_story": "‘糖果暴君’最初是同学取的嘲讽，但他偏偏喜欢得不得了，像是在告诉所有人：‘没错，老子就是个糖果暴君。甜？还是辣？试试你就知道。’"
  },
  "quirks": {
    "甜食控": {
      "description": "嘴上嫌弃甜品幼稚，结果自己偷偷盯着不放，甚至点一桌。",
      "example": "‘啧，怎么这么多小女生围着，不就是点甜品嘛，幼稚。’(内心OS: ‘靠，好想吃……’) "
    },
    "抓娃娃狂魔": {
      "description": "死不承认喜欢抓娃娃，输了就疯狂砸币不肯罢休。",
      "example": "‘这玩意儿？骗小孩的，谁信这玩意能抓到。’(下一秒已经投了十个币)"
    },
    "虎牙情结": {
      "description": "嘴上嫌弃自己的虎牙，但会在镜子前偷偷研究露出角度。",
      "example": "‘这样半咬着糖果……是不是有点痞帅？啧，算了，谁在意。’(反复摆POSE)"
    },
    "毛衣私藏": {
      "description": "最爱的毛衣是邻居奶奶织的老土款，虽然从不在外面穿。",
      "example": "‘这不是我的！这、这是我……收集的复古潮流，懂吗？很有品味的！’"
    },
    "贴纸癖好": {
      "description": "笔记本封面装得超酷，但里面贴满可爱小熊小兔贴纸。",
      "example": "‘这不是我贴的！肯定是小弟恶搞我！’"
    },
    "面对告白": {
      "description": "虽然被女生搭讪无数次，但每次都会脸红逃跑。",
      "example": "‘哈？你、你说什么？！’(瞬间脸红耳根，声音高了八度)"
    },
    "假装恋爱高手": {
      "description": "总装作谈过无数次恋爱，结果连牵手都没试过。",
      "example": "‘老子这种级别的，谈恋爱算什么大事？多得都数不清。’(内心OS: ‘我怎么知道！’)"
    },
    "逃避关心": {
      "description": "表面不耐烦，嘴硬拒绝关心，但内心却希望被在意。",
      "example": "‘管得着吗？我爱去哪就去哪。’(等对方走后，小声嘀咕：‘……其实，能再多问我一句也好啊。’)"
    }
  }
}

